-- ============================================================
-- SUHINA - Carga inicial de datos
-- 333 artículos del Excel + albarán histórico Rogimar (10/91748)
-- Migración idempotente: se puede re-ejecutar sin duplicar
-- ============================================================

-- Desactivamos temporalmente los triggers de stock para que la
-- carga de líneas históricas no altere el stock que viene del Excel
ALTER TABLE public.lineas_albaran_compra DISABLE TRIGGER trg_stock_compra;

-- ============ 1) ARTÍCULOS (333 filas) ============

ON CONFLICT (referencia) DO UPDATE SET
  descripcion = EXCLUDED.descripcion,
  familia = EXCLUDED.familia,
  proveedor_habitual = EXCLUDED.proveedor_habitual,
  precio_compra_referencia = EXCLUDED.precio_compra_referencia,
  stock_actual = EXCLUDED.stock_actual,
  stock_minimo = EXCLUDED.stock_minimo,
  activo = EXCLUDED.activo;

-- ============ 2) CABECERAS DE ALBARANES DE COMPRA (19 albaranes) ============

ON CONFLICT DO NOTHING;

-- ============ 3) LÍNEAS DE ALBARÁN (487 líneas) ============
-- Borramos primero para que la migración sea idempotente
DELETE FROM public.lineas_albaran_compra WHERE albaran_id IN (
  SELECT id FROM public.albaranes_compra WHERE numero_factura = '10/91748'
);

;

-- Re-activar el trigger de stock para futuros albaranes
ALTER TABLE public.lineas_albaran_compra ENABLE TRIGGER trg_stock_compra;

-- ============ FIN DE MIGRACIÓN ============
-- Resultado esperado:
--   articulos: 333 filas
--   albaranes_compra: 19 filas (todas con factura 10/91748)
--   lineas_albaran_compra: 487 filas
--   Caso de prueba: SELECT precio_unitario_neto FROM lineas_albaran_compra
--                   WHERE referencia = 'BG70430004' LIMIT 1;
--   Esperado: 0.9717